codeSnippetEN:
static int divide(int a, int b) {
  if (b == 0) throw new IllegalArgumentException("Zero!");
  return a / b;
}

try {
  System.out.println(divide(10, 0));
} catch (IllegalArgumentException e) {
  System.out.println(e.getMessage());
}

